-- =============================================================================
-- Lab Wizard — Bulk Data Import
-- =============================================================================
--
-- BEFORE RUNNING THIS:
--   1. Run supabase-schema.sql first (creates the tables)
--   2. Sign up in the app with your email + password (creates your auth user)
--   3. Go to Supabase Dashboard → Authentication → Users
--   4. Copy YOUR user ID (the long UUID next to your email)
--   5. Paste it below where it says 'YOUR-USER-ID-HERE'
--
-- =============================================================================

-- >>> PASTE YOUR USER ID HERE (replace the placeholder) <<<
-- :user_id := 'YOUR-USER-ID-HERE'
-- Then highlight everything below and click Run

DO $$
DECLARE
  v_user_id uuid := 'YOUR-USER-ID-HERE';  -- <<< REPLACE THIS WITH YOUR USER ID
BEGIN
  -- Sanity check — make sure the user exists
  IF NOT EXISTS (SELECT 1 FROM auth.users WHERE id = v_user_id) THEN
    RAISE EXCEPTION 'User ID % not found in auth.users. Sign up in the app first, then copy your user ID from Dashboard → Authentication → Users.', v_user_id;
  END IF;

  -- ============ CHEMICALS (160 items) ============
  ON CONFLICT (id) DO NOTHING;

  -- ============ APPARATUS (105 items) ============
  ON CONFLICT (id) DO NOTHING;

  RAISE NOTICE 'Import complete! Inserted % chemicals and % apparatus.',
    (SELECT count(*) FROM public.chemicals WHERE user_id = v_user_id),
    (SELECT count(*) FROM public.apparatus WHERE user_id = v_user_id);
END $$;
